class Network(BaseModel):
    """
    Configures network isolation settings for the sandboxed bash environment, including domain restrictions, Unix socket access, and custom proxy configuration.
    """

    model_config = ConfigDict(
        extra="allow",
    )
    allow_unix_sockets: list[str] | None = Field(
        None,
        alias="allowUnixSockets",
        description="Allow Unix domain sockets for local IPC (SSH agent, Docker, etc.). Provide an array of specific paths. Defaults to blocking if not specified. See https://code.claude.com/docs/en/sandboxing#network-isolation",
    )
    allow_local_binding: bool | None = Field(
        None,
        alias="allowLocalBinding",
        description="Allow binding to local network addresses (e.g., localhost ports). Defaults to false if not specified. See https://code.claude.com/docs/en/sandboxing#network-isolation",
    )
    http_proxy_port: int | None = Field(
        None,
        alias="httpProxyPort",
        description="HTTP proxy port to use for network filtering. If not specified, a proxy server will be started automatically. See https://code.claude.com/docs/en/sandboxing#custom-proxy-configuration",
        ge=1,
        le=65535,
    )
    socks_proxy_port: int | None = Field(
        None,
        alias="socksProxyPort",
        description="SOCKS proxy port to use for network filtering. If not specified, a proxy server will be started automatically. See https://code.claude.com/docs/en/sandboxing#custom-proxy-configuration",
        ge=1,
        le=65535,
    )
    allow_all_unix_sockets: bool | None = Field(
        None,
        alias="allowAllUnixSockets",
        description="Allow all Unix domain socket connections. If true, this overrides allowUnixSockets. See https://code.claude.com/docs/en/sandboxing#network-isolation",
    )
    allowed_domains: list[AllowedDomain] | None = Field(
        None,
        alias="allowedDomains",
        description="Allowlist of network domains for sandboxed commands. Supports wildcard patterns like *.example.com. See https://code.claude.com/docs/en/sandboxing#network-isolation",
    )
    denied_domains: list[DeniedDomain] | None = Field(
        None,
        alias="deniedDomains",
        description="Blocklist of network domains for sandboxed commands. Blocks specific domains even when a broader allowedDomains wildcard would otherwise permit them. Supports wildcard patterns like *.example.com. See https://code.claude.com/docs/en/sandboxing#network-isolation",
    )
    allow_managed_domains_only: bool | None = Field(
        None,
        alias="allowManagedDomainsOnly",
        description="(Managed settings only) Only allowedDomains and WebFetch(domain:...) allow rules from managed settings are respected. User, project, local, and flag settings domains are ignored. Denied domains are still respected from all sources. Non-allowed domains are automatically blocked without user prompts. See https://code.claude.com/docs/en/sandboxing#network-isolation",
    )
    allow_mach_lookup: list[AllowMachLookupItem] | None = Field(
        None,
        alias="allowMachLookup",
        description="macOS only. Additional XPC/Mach service names the sandbox may look up. Supports a single trailing * for prefix matching. Needed for tools that communicate via XPC such as the iOS Simulator or Playwright. See https://code.claude.com/docs/en/sandboxing#network-isolation",
        examples=[["com.apple.coresimulator.*"]],
    )


