class Filesystem(BaseModel):
    """
    Filesystem access control for sandboxed commands. See https://code.claude.com/docs/en/sandboxing#filesystem-isolation
    """

    model_config = ConfigDict(
        extra="allow",
    )
    allow_write: list[AllowWriteItem] | None = Field(
        None,
        alias="allowWrite",
        description="Paths where subprocesses are allowed to write. Supports prefixes: // (absolute), ~/ (home directory), / (relative to settings file), ./ or no prefix (relative path). See https://code.claude.com/docs/en/sandboxing#granting-subprocess-write-access-to-specific-paths",
    )
    deny_write: list[DenyWriteItem] | None = Field(
        None,
        alias="denyWrite",
        description="Paths where subprocesses are explicitly denied write access. Takes precedence over allowWrite. See https://code.claude.com/docs/en/sandboxing#filesystem-isolation",
    )
    deny_read: list[DenyReadItem] | None = Field(
        None,
        alias="denyRead",
        description="Paths where subprocesses are explicitly denied read access. See https://code.claude.com/docs/en/sandboxing#filesystem-isolation",
    )
    allow_read: list[AllowReadItem] | None = Field(
        None,
        alias="allowRead",
        description="Paths to re-allow reading within denyRead regions. Takes precedence over denyRead for matching paths. See https://code.claude.com/docs/en/sandboxing#granting-subprocess-write-access-to-specific-paths",
    )
    allow_managed_read_paths_only: bool | None = Field(
        None,
        alias="allowManagedReadPathsOnly",
        description="(Managed settings only) When true, only allowRead paths from managed settings are used; user, project, and local allowRead entries are ignored. denyRead still merges from all sources. See https://code.claude.com/docs/en/sandboxing#filesystem-isolation",
    )


