class Sandbox(BaseModel):
    """
    Sandbox execution configuration. See https://code.claude.com/docs/en/sandboxing
    """

    model_config = ConfigDict(
        extra="allow",
    )
    network: Network | None = Field(
        None,
        description="Configures network isolation settings for the sandboxed bash environment, including domain restrictions, Unix socket access, and custom proxy configuration.",
    )
    ignore_violations: dict[str, list[str]] | None = Field(
        None,
        alias="ignoreViolations",
        description='Map of command patterns to filesystem paths to ignore violations for. Use "*" to match all commands',
    )
    excluded_commands: list[str] | None = Field(
        None,
        alias="excludedCommands",
        description='Commands that should never run in the sandbox (e.g., ["git", "docker"]). See https://code.claude.com/docs/en/sandboxing#configure-sandboxing',
    )
    auto_allow_bash_if_sandboxed: bool | None = Field(
        True,
        alias="autoAllowBashIfSandboxed",
        description="Automatically allow bash commands without prompting when they run in the sandbox. Only applies to commands that will run sandboxed. See https://code.claude.com/docs/en/sandboxing#sandbox-modes",
    )
    enable_weaker_network_isolation: bool | None = Field(
        False,
        alias="enableWeakerNetworkIsolation",
        description="macOS only. Allow access to the system TLS trust service (com.apple.trustd.agent) in the sandbox. Required for Go-based tools like gh, gcloud, and terraform to verify TLS certificates when using httpProxyPort with a MITM proxy and custom CA. Reduces security by opening a potential data exfiltration path. Default: false. See https://code.claude.com/docs/en/settings#sandbox-settings",
    )
    enable_weaker_nested_sandbox: bool | None = Field(
        None,
        alias="enableWeakerNestedSandbox",
        description="Enable weaker sandbox mode for unprivileged docker environments where --proc mounting fails. This significantly reduces the strength of the sandbox and should only be used when this risk is acceptable. Default: false (secure). See https://code.claude.com/docs/en/sandboxing#limitations",
    )
    allow_unsandboxed_commands: bool | None = Field(
        None,
        alias="allowUnsandboxedCommands",
        description="Allow commands to run outside the sandbox via the dangerouslyDisableSandbox parameter. When false, the dangerouslyDisableSandbox parameter is completely ignored and all commands must run sandboxed. Default: true. See https://code.claude.com/docs/en/sandboxing#limitations",
    )
    enabled: bool | None = Field(
        None,
        description="Enable sandboxed bash. See https://code.claude.com/docs/en/sandboxing#enable-sandboxing",
    )
    filesystem: Filesystem | None = Field(
        None,
        description="Filesystem access control for sandboxed commands. See https://code.claude.com/docs/en/sandboxing#filesystem-isolation",
    )
    ripgrep: Ripgrep | None = Field(
        None,
        description="Custom ripgrep configuration for Claude Code's bundled ripgrep support. Overrides the bundled binary and arguments.",
    )


